// // This module selects the alternative clock signal when the adjust input is low and the primary clock signal when the adjust input is high.
module top_module(
	input clk, adj_clk,
	input wire adjust,
	output clock
    );reg clock_reg;

always @* begin
	if (adjust == 0) 
		clock_reg = clk;
	else 
	    clock_reg = adj_clk;

end

assign clock = clock_reg;

endmodule
